const wh = $input.first().json;
const b = wh.body || {};

const action = String(b.action || '').trim();
const child_ticket_id = String(b.child_ticket_id || '').trim();
const origin_ticket_id = String(b.origin_ticket_id || '').trim();

const acceptedActions = ['close_origin', 'child_solved', 'child_closed', ''];

let validation_error = null;
if (!acceptedActions.includes(action)) {
  validation_error = 'invalid_action';
} else if (!origin_ticket_id || origin_ticket_id === '0') {
  validation_error = 'invalid_origin_ticket_id';
} else if (!child_ticket_id || child_ticket_id === '0') {
  validation_error = 'invalid_child_ticket_id';
} else if (origin_ticket_id === child_ticket_id) {
  validation_error = 'origin_and_child_are_same_ticket';
}

return [{ json: {
  action,
  child_ticket_id,
  origin_ticket_id,
  agent_name: b.agent_name || '',
  agent_email: b.agent_email || '',
  payload_valid: !validation_error,
  validation_error
} }];

const wh = $('Extrair Dados do Webhook').first().json;
const child = $('Validar Ticket Filho Fechado').first().json;
return [{ json: {
  status: 'done',
  origin_ticket_id: wh.origin_ticket_id,
  child_ticket_id: wh.child_ticket_id,
  child_status: child.child_status,
  agent_name: wh.agent_name,
  cleaned_field: true,
  removed_tag: true,
  origin_status_set: 'solved'
} }];

const wh = $('Extrair Dados do Webhook').first().json;
return [{ json: {
  status: 'skipped',
  reason: wh.validation_error || 'invalid_payload',
  payload: wh
} }];

const wh = $('Extrair Dados do Webhook').first().json;
const ticket = $input.first().json.ticket || {};
const child_status = ticket.status || '';
const child_is_closed = ['solved', 'closed'].includes(child_status);

return [{ json: {
  ...wh,
  child_status,
  child_is_closed,
  child_subject: ticket.subject || '',
  child_assignee_id: ticket.assignee_id || null
} }];

const wh = $('Extrair Dados do Webhook').first().json;
const child = $('Validar Ticket Filho Fechado').first().json;
return [{ json: {
  status: 'skipped',
  reason: 'child_ticket_not_solved_or_closed',
  origin_ticket_id: wh.origin_ticket_id,
  child_ticket_id: wh.child_ticket_id,
  child_status: child.child_status
} }];

const wh = $('Extrair Dados do Webhook').first().json;

function collectRaw(value, seen = new Set()) {
  if (value === null || value === undefined) return [];
  if (typeof value === 'string') return [value];
  if (typeof value !== 'object') return [];
  if (seen.has(value)) return [];
  seen.add(value);

  let out = [];
  for (const v of Object.values(value)) {
    out = out.concat(collectRaw(v, seen));
  }
  return out;
}

function tryParseJson(candidate) {
  if (!candidate || typeof candidate !== 'string') return null;
  const attempts = [
    candidate,
    candidate.replace(/\\"/g, '"'),
    candidate.replace(/^"|"$/g, ''),
    candidate.replace(/^"|"$/g, '').replace(/\\"/g, '"')
  ];

  for (const attempt of attempts) {
    try {
      const parsed = JSON.parse(attempt);
      if (typeof parsed === 'string') {
        const nested = tryParseJson(parsed);
        if (nested) return nested;
      }
      if (parsed && typeof parsed === 'object') return parsed;
    } catch (e) {}
  }
  return null;
}

function extractJsonObjects(raw) {
  const candidates = [];
  candidates.push(raw);

  const firstBrace = raw.indexOf('{');
  const lastBrace = raw.lastIndexOf('}');
  if (firstBrace >= 0 && lastBrace > firstBrace) {
    candidates.push(raw.slice(firstBrace, lastBrace + 1));
  }

  const firstQuoteBrace = raw.indexOf('"{');
  const lastBraceQuote = raw.lastIndexOf('}"');
  if (firstQuoteBrace >= 0 && lastBraceQuote > firstQuoteBrace) {
    candidates.push(raw.slice(firstQuoteBrace + 1, lastBraceQuote + 1));
  }

  return candidates.map(tryParseJson).filter(Boolean);
}

const rawStrings = collectRaw($json);
const parsedBodies = rawStrings.flatMap(extractJsonObjects);

const details = [];
for (const body of parsedBodies) {
  const base = body.details && body.details.base;
  if (Array.isArray(base)) details.push(...base);
}

function cleanFieldName(description) {
  const text = String(description || 'Campo obrigatório pendente').trim();
  const marker = ': é necessário';
  if (text.includes(marker)) return text.split(marker)[0].trim();
  return text.replace(/:.*$/, '').trim() || text;
}

const missingFieldsRaw = details.map(d => {
  const description = d.description || 'Campo obrigatório pendente';
  return {
    name: cleanFieldName(description),
    description,
    ticket_field_id: d.ticket_field_id || null,
    ticket_field_type: d.ticket_field_type || null
  };
});

const seenFields = new Set();
const missingFields = [];
for (const field of missingFieldsRaw) {
  const key = field.ticket_field_id ? `id:${field.ticket_field_id}` : `desc:${field.description}`;
  if (seenFields.has(key)) continue;
  seenFields.add(key);
  missingFields.push(field);
}

const missingText = missingFields.length
  ? missingFields.map(f => `• ${f.name}`).join('\n')
  : '• Não foi possível extrair a lista de campos. Abra o ticket de origem e verifique os campos obrigatórios do formulário.';

const note = [
  '⚠️ Origem não foi encerrada automaticamente',
  '',
  'O ticket filho #' + wh.child_ticket_id + ' foi encerrado, mas o Zendesk bloqueou o fechamento do ticket de origem #' + wh.origin_ticket_id + ' porque ainda existem campos obrigatórios pendentes.',
  '',
  'Preencha no ticket de origem:',
  missingText,
  '',
  'Depois de preencher os campos obrigatórios no ticket de origem, aplique novamente a macro de encerramento neste ticket filho.',
  'A macro remove a trava de reprocessamento e tenta fechar a origem novamente.'
].join('\n');

return [{ json: {
  status: 'origin_close_failed',
  reason: 'zendesk_validation_error',
  origin_ticket_id: wh.origin_ticket_id,
  child_ticket_id: wh.child_ticket_id,
  agent_name: wh.agent_name,
  agent_email: wh.agent_email,
  missing_fields: missingFields,
  missing_fields_text: missingText,
  nota_falha_fechamento: note,
  raw_error: $json
} }];

const failure = $('Preparar Nota Falha Fechamento').first().json;
return [{ json: {
  status: 'origin_close_failed_notified',
  origin_ticket_id: failure.origin_ticket_id,
  child_ticket_id: failure.child_ticket_id,
  missing_fields: failure.missing_fields,
  notified_child: true,
  notified_origin: true
} }];
